use std::sync::mpsc;
use std::thread;

struct SensorReading {
    id: u64,
    value: f64,
}

fn process_reading(reading: SensorReading) -> f64 {
    println!("Processing sensor ID: {}", reading.id);
    // Simulate some computation delay
    thread::sleep(std::time::Duration::from_millis(50));
    reading.value * 1.2
}

fn main() -> std::io::Result<()> {
    const DATA_POINTS: usize = 8;
    let (tx, rx) = mpsc::channel::<SensorReading>();

    for i in 0..DATA_POINTS {
        let reading = SensorReading { id: (i + 1) as u64, value: (i + 1) as f64 * 10.0 };
        tx.send(reading).unwrap();
    }

    drop(tx); // Close the sender so the receiver knows when to stop

    let mut handles = vec![];
    for received_reading in rx {
        let handle = thread::spawn(move || {
            process_reading(received_reading)
        });
        handles.push(handle);
    }

    let results: Vec<f64> = handles.into_iter().map(|h| h.join().unwrap()).collect();

    println!("nAll data processed concurrently. First result received: {:.2}", results.get(0).unwrap());
    Ok(())
}

use tokio::sync::mpsc;
use std::time::Duration;

struct Job {
    id: u32,
    name: String,
}

async fn run_job(job: Job, sender: mpsc::Sender<String>) -> Result<(), Box<dyn std::error::Error>> {
    println!("Starting job {} for {}. This will take 1 second.", job.id, job.name);
    tokio::time::sleep(Duration::from_secs(1)).await;
    let message = format!("Job {} finished successfully on {}", job.id, job.name);
    sender.send(message).await.ok();
    Ok(())
}

#[tokio::main]
async fn main() -> Result<(), Box<dyn std::error::Error>> {
    let (tx, mut rx) = mpsc::channel::<String>(32);
    let jobs_to_run = vec![Job { id: 1, name: "Frontend Build".to_string() }, Job { id: 2, name: "Database Migration".to_string() }, Job { id: 3, name: "API Health Check".to_string() }];

    let mut handles = vec![];
    for job in jobs_to_run {
        let tx_clone = tx.clone();
        let handle = tokio::spawn(async move {
            match run_job(job, tx_clone).await {
                Ok(_) => (), 
                Err(e) => eprintln!("Error running job: {}", e)
            }
        });
        handles.push(handle);
    }

    drop(tx); // Drop the original sender to allow receiver loop to terminate when all spawned tasks are done

    let mut results = vec![];
    while let Some(message) = rx.recv().await {
        println!("n[Result Received]: {}", message);
        results.push(format!("Completed: {}", message));
    }

    println!("nAll tasks have reported back.");
    for result in results {
        println!("Final Log Entry: {}", result);
    }

    Ok(())
}

use std::collections::VecDeque;
use std::sync::{Arc, Mutex};

struct MessageBuffer {
    id: u64,
    data_len: usize,
    payload: Vec<u8>,
}

struct PubSubBroker {
    topics: Arc<Mutex<std::collections::HashMap<String, VecDeque<Arc<Mutex<MessageBuffer>>>>>>
}

impl PubSubBroker {
    fn new() -> Self {
        PubSubBroker {
            topics: Arc::new(Mutex::new(std::collections::HashMap::new()))
        }
    }

    fn publish(&self, topic: &str, message: Vec<u8>) -> Result<(), String> {
        let buffer = Arc::new(Mutex::new(MessageBuffer { 
            id: rand::random(), 
            data_len: message.len(), 
            payload: message 
        }));

        let mut topics_guard = self.topics.lock().unwrap();
        let messages_for_topic = topics_guard.entry(String::from(topic)).or_insert_with(VecDeque::new);

        messages_for_topic.push_back(buffer.clone());
        Ok(())
    }

    fn subscribe(&self, topic: &str) -> Vec<Arc<Mutex<MessageBuffer>>> {
        let topics_guard = self.topics.lock().unwrap();
        match topics_guard.get(topic) {
            Some(messages) => messages.iter().map(|msg| msg.clone()).collect(),
            None => Vec::new(),
        }
    }
}

fn main() -> Result<(), Box<dyn std::error::Error>> {
    let broker = PubSubBroker::new();

    let topic_name = String::from("system_alerts");
    let message1 = b"Critical failure detected".to_vec();
    let message2 = b"Heartbeat signal received".to_vec();

    broker.publish(&topic_name, message1)?; 
    broker.publish(&topic_name, message2)?; 

    let subscribers = broker.subscribe(&topic_name);

    println!("Found {} messages for topic: {}", subscribers.len(), topic_name); 

    for buffer_arc in subscribers {
        let buffer_guard = buffer_arc.lock().unwrap();
        println!("Processing message ID: {}, Size: {}", buffer_guard.id, buffer_guard.data_len);
    }

    Ok(())
}

use tokio::sync::{mpsc, oneshot};
use std::time::Duration;
use tokio::time::sleep;
use futures::future::join_all;

struct Message {
    kind: String,
    data: String,
}

#[tokio::main]
async fn main() -> Result<(), Box<dyn std::error::Error>> {
    let (tx, mut rx) = mpsc::channel::<Message>(32);

    let processor_task = tokio::spawn(async move {
        while let Some(message) = rx.recv().await {
            match message.kind.as_str() {
                "CONNECT" => {
                    println!("Handling connection setup for: {}", message.data);
                    sleep(Duration::from_millis(50)).await;
                    println!("Connection established successfully.");
                }
                "DATA" => {
                    println!("Processing data transfer for: {}", message.data);
                    sleep(Duration::from_millis(100)).await;
                    println!("Data acknowledged.");
                }
                _ => {
                    println!("Unknown message type received: {}", message.kind);
                }
            }
        }
    });

    let sender_handle = tokio::spawn(async move {
        sleep(Duration::from_millis(10)).await;
        tx.send(Message { kind: "CONNECT".to_string(), data: "client_a".to_string() }).await.unwrap();
        sleep(Duration::from_millis(20)).await;
        tx.send(Message { kind: "DATA".to_string(), data: "body1".to_string() }).await.unwrap();
        sleep(Duration::from_millis(30)).await;
        tx.send(Message { kind: "CONNECT".to_string(), data: "client_b".to_string() }).await.unwrap();
        sleep(Duration::from_millis(50)).await;
        tx.send(Message { kind: "DATA".to_string(), data: "body2".to_string() }).await.unwrap();
    });

    join_all([processor_task, sender_handle]).await;

    Ok(())
}

use std::sync::mpsc;
use std::thread;
use std::time::Duration;

struct WorkerRequest { 
    id: u32,
    payload: String
}

fn main() -> Result<(), Box<dyn std::error::Error>> {
    let (tx_requests, rx_requests) = mpsc::channel::<WorkerRequest>();
    let (tx_ack, rx_ack) = mpsc::channel::<u32>();

    thread::spawn(move || {
        for req in rx_requests.iter() {
            println!("Processing request for unit: {}", req.id);
            thread::sleep(Duration::from_millis(100));
            let ack_result = tx_ack.send(req.id).unwrap();
            println!("Acknowledged task completion for unit: {:?}", ack_result);
        }
    });

    for i in 1..=5 {
        let request = WorkerRequest { 
            id: i,
            payload: format!("Update state for entity {}", i)
        };
        tx_requests.send(request).expect("Failed to send request");
    }

    drop(tx_requests);

    let mut received_acks = 0;
    while let Ok(ack) = rx_ack.recv() {
        received_acks += 1;
        println!("Received confirmation for unit ID: {}", ack);
    }

    Ok(())
}
